            using (new EditorGUILayout.VerticalScope())
            {
                UI.DrawH2("Thank you for licensing Stylized Grass Shader for Unity 6!");

                EditorGUILayout.LabelField("This window houses common functionality and installation information.", EditorStyles.label);

                EditorGUILayout.Space();

                using (new EditorGUILayout.HorizontalScope())
                {
                    GUILayout.FlexibleSpace();
                    if (GUILayout.Button(new GUIContent("<b><size=12>  Write a review</size></b>\n<i>  Support further development</i>", ReviewIcon), UI.Styles.Button, GUILayout.Height(45f), GUILayout.Width(240f)))
                    {
                        AssetInfo.OpenReviewsPage();
                    }
                    GUILayout.FlexibleSpace();
                }
                EditorGUILayout.Space();

            }
            
            EditorGUILayout.Space();

            using (new EditorGUILayout.VerticalScope())
            {
                #if URP
                UI.DrawH2("Quickstart");

                GUILayout.Space(5f);

                using (new EditorGUILayout.HorizontalScope())
                {
                    if (GUILayout.Button("<b><size=12>  Open demo scene</size></b>\n<i>  See the shader in action</i>", UI.Styles.Button, GUILayout.Height(45f)))
                    {
                        StylizedGrassEditor.OpenDemoScene();
                    }
                    if (GUILayout.Button("<b><size=12>  Show prefabs folder</size></b>\n<i>  Ready to use vegetation items</i>", UI.Styles.Button, GUILayout.Height(45f)))
                    {
                        string path = AssetDatabase.GUIDToAssetPath("e0344e232dc935442867c75753f09048");
                        Object folder = AssetDatabase.LoadAssetAtPath<Object>(path);

                        EditorGUIUtility.PingObject(folder);
                    }
